const { chromium } = require('playwright');

const CIVICWEB_BASE = 'https://cityofjerseycity.civicweb.net';
const MEETING_LIST_URL = `${CIVICWEB_BASE}/Portal/MeetingInformation.aspx`;

const browser = await chromium.launch({ headless: true });
const page = await browser.newPage();

// Get recent meetings
await page.goto(MEETING_LIST_URL, { waitUntil: 'networkidle', timeout: 30000 });
const meetings = await page.evaluate((base) => {
  return Array.from(document.querySelectorAll('a.list-link')).slice(0, 2).map(a => ({
    title: a.textContent.trim(),
    url: `${base}${a.getAttribute('href') || ''}`
  }));
}, CIVICWEB_BASE);

const allItems = [];

for (const meeting of meetings) {
  await page.goto(meeting.url, { waitUntil: 'networkidle', timeout: 30000 });
  const folderUrl = await page.evaluate((base) => {
    const links = Array.from(document.querySelectorAll('a'));
    for (const link of links) {
      if (link.textContent.trim().toUpperCase().includes('ORDINANCES') && (link.getAttribute('href') || '').includes('filepro')) {
        const href = link.getAttribute('href');
        return href.startsWith('http') ? href : `${base}${href}`;
      }
    }
    return null;
  }, CIVICWEB_BASE);

  if (!folderUrl) continue;

  await page.goto(folderUrl, { waitUntil: 'networkidle', timeout: 30000 });
  const items = await page.evaluate((base) => {
    return Array.from(document.querySelectorAll('a')).filter(a => /^(Ord\.|Res\.)\s*\d{2,4}-\d{1,4}/i.test(a.textContent.trim())).map(a => {
      const text = a.textContent.trim();
      const m = text.match(/^(Ord\.|Res\.)\s*(\d{2,4}-\d{1,4})/i);
      const prefix = m[1].toLowerCase().startsWith('ord') ? 'Ord' : 'Res';
      return {
        ordinance_num: `${prefix}-${m[2]}`,
        title: text.replace(/\s*-\s*Pdf\s*$/i, '').trim(),
        doc_type: prefix === 'Ord' ? 'ordinance' : 'resolution',
        source_url: `${base}${a.getAttribute('href') || ''}`,
        current_state: /withdrawn/i.test(text) ? 'WITHDRAWN' : 'INTRODUCED'
      };
    });
  }, CIVICWEB_BASE);

  allItems.push(...items);
}

await browser.close();
return allItems;

const { createClient } = require('@supabase/supabase-js');

const supabase = createClient(
  $env.SUPABASE_URL,
  $env.SUPABASE_SERVICE_KEY
);

const VALID_TRANSITIONS = {
  INTRODUCED: ['AMENDED', 'COMMITTEE', 'VOTED', 'WITHDRAWN'],
  AMENDED: ['COMMITTEE', 'VOTED', 'WITHDRAWN'],
  COMMITTEE: ['VOTED', 'WITHDRAWN'],
  VOTED: ['PASSED', 'FAILED'],
  PASSED: [], FAILED: [], WITHDRAWN: []
};

const items = $input.all().map(i => i.json);
const notifiable = [];

for (const item of items) {
  const slug = item.title.toLowerCase().replace(/[^a-z0-9]/g, '_').slice(0, 40);
  const id = `${item.ordinance_num}_${slug}`;

  const { data: existing } = await supabase.from('ordinances').select('id, current_state').eq('id', id).single();

  if (existing) {
    if (existing.current_state !== item.current_state) {
      await supabase.from('ordinances').update({
        previous_state: existing.current_state,
        current_state: item.current_state,
        last_updated: new Date().toISOString(),
        notified_at: null
      }).eq('id', id);
      notifiable.push({ ...item, id });
    }
  } else {
    await supabase.from('ordinances').insert({ id, ...item });
    notifiable.push({ ...item, id });
  }
}

return notifiable;

const { createClient } = require('@supabase/supabase-js');

const supabase = createClient(
  $env.SUPABASE_URL,
  $env.SUPABASE_SERVICE_KEY
);

const { data: profiles } = await supabase.from('profiles').select('*').eq('active', true);
return profiles || [];

const Anthropic = require('@anthropic-ai/sdk');
const client = new Anthropic.default();

const profiles = $input.all().map(i => i.json);
const notifiable = $('State Tracker Upsert').all().map(i => i.json);

if (!notifiable.length) return [];

const results = [];

for (const profile of profiles) {
  const analyzedItems = [];

  for (const item of notifiable) {
    const prompt = `You are a civic intelligence assistant for Jersey City, NJ residents.\n\nAnalyze the following government document and user profile. Return a JSON object only — no markdown, no preamble.\n\nDOCUMENT:\n${item.title} (${item.doc_type})\nStatus: ${item.current_state}\n\nUSER PROFILE:\nWard: ${profile.ward}\nHousing: ${profile.housing}\nTransport: ${profile.transport}\nHas kids: ${profile.has_kids}\nInterests: ${(profile.interests || []).join(', ')}\n\nReturn this exact JSON structure:\n{\n  "plain_title": "short plain-English title",\n  "what_is_happening": "2 sentences max",\n  "personal_impact": "1-2 sentences for THIS user",\n  "relevance_score": <1-10>,\n  "current_status": "${item.current_state}",\n  "status_context": "one sentence",\n  "action_available": <true|false>\n}\n\nOnly return the JSON.`;

    const msg = await client.messages.create({
      model: 'claude-opus-4-20250514',
      max_tokens: 1024,
      messages: [{ role: 'user', content: prompt }]
    });

    let parsed;
    try {
      let text = msg.content[0].text.trim();
      const fence = text.match(/```(?:json)?\s*([\s\S]*?)```/);
      if (fence) text = fence[1].trim();
      parsed = JSON.parse(text);
    } catch { continue; }

    if (parsed.relevance_score >= 5) {
      analyzedItems.push({ ...parsed, ordinance_id: item.id, doc_type: item.doc_type });
    }
  }

  if (analyzedItems.length) {
    analyzedItems.sort((a, b) => b.relevance_score - a.relevance_score);
    results.push({ profile, items: analyzedItems });
  }
}

return results;

const { Resend } = require('resend');
const resend = new Resend($env.RESEND_API_KEY);
const VOTE_BASE = $env.VOTE_BASE_URL || 'https://your-app.vercel.app';

const digests = $input.all().map(i => i.json);
const sent = [];

for (const digest of digests) {
  const { profile, items } = digest;
  const weekDate = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });

  const itemsHtml = items.map(item => {
    const colors = { INTRODUCED:'#3b82f6', AMENDED:'#f59e0b', COMMITTEE:'#8b5cf6', VOTED:'#6366f1', PASSED:'#10b981', FAILED:'#ef4444', WITHDRAWN:'#6b7280' };
    const c = colors[item.current_status] || '#6b7280';
    return `<div style="background:#fff;border:1px solid #e5e7eb;border-radius:8px;padding:20px;margin-bottom:16px;">
      <span style="background:#f3f4f6;color:#374151;font-size:11px;font-weight:600;padding:2px 8px;border-radius:4px;text-transform:uppercase;margin-right:8px;">${item.doc_type}</span>
      <span style="background:${c};color:#fff;font-size:11px;font-weight:600;padding:2px 8px;border-radius:4px;">${item.current_status}</span>
      <h3 style="margin:8px 0;font-size:18px;color:#111827;">${item.plain_title}</h3>
      <p style="color:#4b5563;font-size:14px;">${item.what_is_happening}</p>
      <div style="background:#eff6ff;border-left:3px solid #3b82f6;padding:12px;margin:12px 0;"><strong>What this means for you:</strong> ${item.personal_impact}</div>
      <p style="font-size:13px;color:#6b7280;">${item.status_context}</p>
      <a href="${VOTE_BASE}/api/vote?user=${profile.id}&item=${item.ordinance_id}&vote=up" style="background:#f0fdf4;color:#166534;padding:6px 16px;border-radius:6px;text-decoration:none;margin-right:8px;">&#128077; Support</a>
      <a href="${VOTE_BASE}/api/vote?user=${profile.id}&item=${item.ordinance_id}&vote=down" style="background:#fef2f2;color:#991b1b;padding:6px 16px;border-radius:6px;text-decoration:none;">&#128078; Oppose</a>
    </div>`;
  }).join('');

  const html = `<div style="max-width:600px;margin:0 auto;padding:20px;font-family:-apple-system,sans-serif;">
    <h1 style="text-align:center;">Your Jersey City Digest</h1>
    <p style="text-align:center;color:#6b7280;">Week of ${weekDate} · Ward ${profile.ward}</p>
    ${itemsHtml}
    <p style="text-align:center;font-size:12px;color:#9ca3af;">CivicPulse · Jersey City · <a href="${VOTE_BASE}/unsubscribe?user=${profile.id}">Unsubscribe</a></p>
  </div>`;

  const subject = `\u{1F3D9}\uFE0F JC This Week — ${items[0].plain_title}`;

  const { data, error } = await resend.emails.send({
    from: 'CivicPulse <onboarding@resend.dev>',
    to: [profile.email],
    subject,
    html
  });

  if (!error) sent.push({ email: profile.email, itemCount: items.length });
}

return sent;

const { createClient } = require('@supabase/supabase-js');
const supabase = createClient($env.SUPABASE_URL, $env.SUPABASE_SERVICE_KEY);

const notifiable = $('State Tracker Upsert').all().map(i => i.json);
const ids = notifiable.map(i => i.id);

if (ids.length) {
  await supabase.from('ordinances').update({ notified_at: new Date().toISOString() }).in('id', ids);
}

return [{ markedNotified: ids.length }];
